        var hardware=Panel();hardware.Margin=new Thickness(0,12,0,0);var hs=new StackPanel();hardware.Child=hs;hs.Children.Add(Heading("TESTED HARDWARE / PERFORMANCE CONTEXT"));hs.Children.Add(new TextBlock{Text="CPU, GPU, 메모리, 메인보드와 저장장치 구성을 점수와 함께 기록합니다.",Foreground=new SolidColorBrush(Color.FromRgb(104,112,125)),Margin=new Thickness(0,6,0,10)});var data=new DataGrid{ItemsSource=_viewModel.HardwareItems,AutoGenerateColumns=false,IsReadOnly=true,CanUserAddRows=false,Height=260};data.Columns.Add(new DataGridTextColumn{Header="분류",Binding=new Binding("Category"),Width=120});data.Columns.Add(new DataGridTextColumn{Header="하드웨어",Binding=new Binding("Name"),Width=new DataGridLength(2,DataGridLengthUnitType.Star)});data.Columns.Add(new DataGridTextColumn{Header="사양",Binding=new Binding("Value"),Width=new DataGridLength(3,DataGridLengthUnitType.Star)});hs.Children.Add(data);root.Children.Add(hardware);
